```class Solution {
public:
    bool canChange(string start, string target) {
        int lCount = 0, rCount = 0;
        for (int i = 0; i < start.size(); ++i) {
            if (start[i] == 'L' && target[i] != 'L') ++lCount;
            if (start[i] == 'R' && target[i] != 'R') ++rCount;
            if (target[i] == 'L' && start[i] != 'L') --lCount;
            if (target[i] == 'R' && start[i] != 'R') --rCount;
            if (lCount < 0 || rCount < 0) return false;
        }
        return lCount == 0 && rCount == 0;
    }
};
